import { useState } from "react";

function Home(){

    const [courses,setCourses] = useState([]);

    const scholarshipData = {

        Government:[
            "UPSC Coaching",
            "SSC Coaching",
            "Banking"
        ],

        Engineering:[
            "B.Tech",
            "M.Tech",
            "Diploma Engineering"
        ],

        Medical:[
            "MBBS",
            "BDS",
            "Nursing",
            "Pharmacy"
        ],

        Management:[
            "MBA",
            "BBA"
        ],

        Computer:[
            "BCA",
            "MCA",
            "BSc IT",
            "Data Science"
        ]

    };


    const showCourses = (category)=>{

        setCourses(scholarshipData[category]);

    }


    return(

        <div className="container">

            <h2>Scholarship Categories</h2>

            <div className="card-container">

                <div
                className="card"
                onClick={()=>showCourses("Government")}
                >
                    Government
                </div>

                <div
                className="card"
                onClick={()=>showCourses("Engineering")}
                >
                    Engineering
                </div>

                <div
                className="card"
                onClick={()=>showCourses("Medical")}
                >
                    Medical
                </div>

                <div
                className="card"
                onClick={()=>showCourses("Management")}
                >
                    Management
                </div>

                <div
                className="card"
                onClick={()=>showCourses("Computer")}
                >
                    Computer
                </div>

            </div>


            <h3>Available Courses</h3>

            {
                courses.map((item,index)=>(

                    <p key={index}>{item}</p>

                ))
            }

        </div>

    )

}

export default Home;
